form:Form.form:Scripts:
		//Este lo va a llamar cuando cambia de seleccionar una licencia con familiar o no
function datos_tipo(myThis)
{ 
	if(myThis.ID()=='oi_familiar_per')
	{   		  		
		if(!Ctrl('oi_familiar_per').GetEnabled()) return;						

		if(Ctrl('oi_familiar_per').GetXValue()!="")
		{    			
			var np = new NomadProxy("", ut);
			var nSQL = np.SQLService();       
			var param = nSQL.GetOBJ(Ctrl("main").getResource("qry_tipo_fliar"), "<PARAM oi_familiar_per=\""+Ctrl('oi_familiar_per').GetXValue()+"\" />");			
			Ctrl('oi_tipo_familiar').SetXValue(param.oi_tipo_familiar.toString()); 					

			var nombre = Ctrl("oi_familiar_per").GetCValue().split("-");		                                         		                                         			
			Ctrl('o_licencia_per').SetXValue(Trim(nombre[1])); 
			calcular_dias(myThis);	
		}	
		else
		{
			Ctrl('o_licencia_per').SetXValue(""); 
			Ctrl('oi_tipo_familiar').SetXValue("");
			Ctrl('e_saldo').SetXValue("");
			calcular_dias(Ctrl('oi_licencia')); 		
		}		
	}
}


function hab_tipofliar(myThis)
{ 	                                         
	var codLicFliar = Ctrl('codLicFliar').GetXValue().toString();     
	if(codLicFliar!='')
	{
		//si el valor que llega es la licencia - valido que sea de tipo familiar enfermo segun el parametro
		if(myThis.ID()=='oi_licencia')
		{		
			if(Ctrl("oi_licencia").GetXValue() != '')
			{             				
				//Recupero el codigo de la licencia - asociada al tipo de hora seleccionada en el control de oi_licencia
				var np = new NomadProxy("", ut);
				var nSQL = np.SQLService();       
				var param = nSQL.GetOBJ(Ctrl("main").getResource("qry_CodLic"), "<PARAM oi_licencia=\""+Ctrl('oi_licencia').GetXValue()+"\" />");	    		    	

				var c_lic = param.c_licencia; 			    		    						  		


				if(codLicFliar.toString() == c_lic.toString())
				{	
					Ctrl('oi_familiar_per').SetEnabled(true);
				}        	
				else
				{
					Ctrl('oi_familiar_per').SetXValue("");
					Ctrl('oi_familiar_per').SetEnabled(false);
				}	
			}
			else
			{
				Ctrl('oi_familiar_per').SetXValue(""); 	
			}		
		}
	}       
	//En onchange del control de licencias tiene que llamar al calcular dias despues de habilitar al combo de tipo de familiar
	calcular_dias(myThis); 
}  


function OnLoad()
{
	//Inicio el Periodo	
	if (Ctrl("ESPERANZA_PERIODO").GetXValue()=="") 
	{
		if (Ctrl("periodo").GetXValue()!="") 
			Ctrl("ESPERANZA_PERIODO").SetXValue(Ctrl("periodo").GetXValue()+'01');
		else
			Ctrl("ESPERANZA_PERIODO").SetXValue(date2str(NowDate()).substr(0,6));
	}

	//Obtengo los Parametros
	var objMONTH=Ctrl("ESPERANZA_PERIODO");
	var lastDate=new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10), 1);

	//Creo el CONTROL
	MyOBJ=HTMLTimeBarSelected("ESPERANZA","",ChangeTime,OnClickHorario);
	MyOBJ.SetAxisMode("SERIE/DATE");
	MyOBJ.SetAxisDate(objMONTH.GetXValue()+"01",date2str(lastDate), 1, 1, 12);
	MyOBJ.ShowMonth=false;

 	//Agrego la Serie
	MyOBJ.AddSerie("BLQ", "Cerrado"  ,"Liquidaciones Cerradas");
	MyOBJ.AddSerie("HOR", "Horarios" ,"Horarios Asignados"    );
	MyOBJ.AddSerie("LIC", "Licencias","Licencias Definidas"   );
	MyOBJ.AddSerie("TUR", "Turnos"   ,"Turnos Asignados"      );

	//Dibujo la Lista VACIA
	MyOBJ.Draw();


	LiqCloses=new NomadXML(Ctrl("main").GetLastDoc("LIQ"  ));


	//Cargo las Referencias
	NomadTimeout("LoadReferences();", 100, "Cargando Referencias..."); 

	if(Ctrl("main").GetMode()=='EDIT' || Ctrl("main").GetMode()=='NEW')
	{
		Ctrl('oi_familiar_per').SetEnabled(false);	
	}

	var v_param;

	//Recupero el codigo de la licencia por familiar en el parametro
	var np = new NomadProxy("", ut);
	var nSQL = np.SQLService();       
	var param = nSQL.GetOBJ(Ctrl("main").getResource("QRY_PARAMETRO"), "");	

	//Si existe el parametro - controla licencia
	if (typeof (param.d_valor) != "undefined")
	{
		v_param = param.d_valor.toString();		
	}
	else
	{
		v_param = "";
	} 	

	Ctrl('codLicFliar').SetXValue(v_param);	

}   


var Edit=false;
var New=false;

function RefreshControls()
{
	//Desactivo los Controles de Cambio
	if (MyLICSel==null)
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	} else 
	if (Edit)
	{
		CtrlEnabled("DATA"  , true );
		CtrlEnabled("ADD"   , false);
		CtrlEnabled("EDIT"  , false);
		CtrlEnabled("DELETE", false);
		CtrlEnabled("BACK"  , false);
		CtrlEnabled("ACCEPT", true );
		CtrlEnabled("CANCEL", true );
	} else
	{
		CtrlEnabled("DATA"  , false);
		CtrlEnabled("ADD"   , true );
		CtrlEnabled("EDIT"  , true );
		CtrlEnabled("DELETE", true );
		CtrlEnabled("BACK"  , true );
		CtrlEnabled("ACCEPT", false);
		CtrlEnabled("CANCEL", false);
	}
}

function RefreshCustomSerie(MyOBJ, myserie)
{   
	if (myserie!="LIC") return;

	var objMONTH=Ctrl("ESPERANZA_PERIODO");
	var ff, fi, now, cur, MyROW, t, oi_licencia;
	var firstDate=date2int(new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10)-1, 1));
	var lastDate =date2int(new Date(parseInt(objMONTH.GetXValue().substr(0,4),10), parseInt(objMONTH.GetXValue().substr(4,2),10), 1));

	//Limpio el DIA
	MyOBJ.ClearValue("LIC");     

	for (t=0; t<Ctrl("arrLicencias").CountRow(); t++)
	{
		MyROW=Ctrl("arrLicencias").GetRow(t);

		if ((MyLICSel==null) || (MyROW.GetAttr("id")!=MyLICSel.GetAttr("id")))
		{
			oi_licencia=MyROW.GetAttr("oi_licencia");
			fi=date2int(str2date(MyROW.GetAttr("f_inicio")));
			ff=date2int(str2date(MyROW.GetAttr("f_fin")));
			if (MyROW.GetAttr("f_interrupcion")!="") ff=date2int(str2date(MyROW.GetAttr("f_interrupcion")));
		} else
		{
			oi_licencia=Ctrl("oi_licencia").GetXValue();
			fi=date2int(str2date(Ctrl("f_inicio").GetXValue()));
			ff=date2int(str2date(Ctrl("f_fin"   ).GetXValue()));
			if (Ctrl("f_interrupcion").GetXValue()!="") ff=date2int(str2date(Ctrl("f_interrupcion").GetXValue()));
		}
		if (ff<firstDate) continue;
		if (fi>lastDate) continue;        

		//Obtengo el color segun el tipo de hora
		dd=null;
		for (key in MyDAT["LIC"].arr)
			if (MyDAT["LIC"].arr[key].lic==oi_licencia)
				dd=MyDAT["LIC"].arr[key];

		//Calculo de Color		
		color="AA0000";
		if ((dd!=null) && (dd.color)) color=dd.color;

		//Obtengo 
		newval=MyOBJ.SetValue(
			"LIC",
			fi,
			ff+1,
			"Licencia",
			color,
			color,
			"Licencia "+(dd==null?"":dd.label)+" desde "+int2date(fi)+(MyROW.GetAttr("f_interrupcion")==""?" hasta ":" interrumpida ")+int2date(ff),
			"BAR"
		);              
		newval.MyID    =MyROW.GetAttr("id");
		newval.selected=MyLICSel?((MyROW.GetAttr("id")==MyLICSel.GetAttr("id"))?true:false):false;
	}

}



function OnClickHorario(obj, dte, value)
{	              
	var MyROW;                            
	if (value.MyID?false:true) return;
	if (Edit) return;   

  	MyROW=Ctrl("arrLicencias").GetRowByAttr("id", value.MyID);
	Ctrl("oi_licencia"   ).SetXValue(MyROW.GetAttr("oi_licencia"   ));
	Ctrl("f_inicio"      ).SetXValue(MyROW.GetAttr("f_inicio"      ));
	Ctrl("f_fin"         ).SetXValue(MyROW.GetAttr("f_fin"         ));
	Ctrl("e_cant_dias"   ).SetXValue(MyROW.GetAttr("e_cant_dias"   ));
	Ctrl("e_anio_corresp").SetXValue(MyROW.GetAttr("e_anio_corresp"));
	Ctrl("f_interrupcion").SetXValue(MyROW.GetAttr("f_interrupcion"));
	Ctrl("o_licencia_per").SetXValue(MyROW.GetAttr("o_licencia_per"));
	Ctrl("oi_familiar_per").SetXValue(MyROW.GetAttr("oi_familiar_per"));

	if(Ctrl("oi_familiar_per").GetXValue()!="")
	{
 		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();       
		var param = nSQL.GetOBJ(Ctrl("main").getResource("qry_tipo_fliar"), "<PARAM oi_familiar_per=\""+Ctrl('oi_familiar_per').GetXValue()+"\" />");			
		Ctrl('oi_tipo_familiar').SetXValue(param.oi_tipo_familiar.toString());
	}
	else
	{
		Ctrl('oi_tipo_familiar').SetXValue("");
	}                                  

	calcularSaldo(MyROW.GetAttr("e_cant_dias"));

	MyLICSel=MyROW;

	New=false;
	ReDrawWait(MyOBJ,"LIC",true, true);
}


function AddLicencia()
{    
	Ctrl('e_saldo').SetXValue('');
	NomadTimeout("internalAddLicencia();",100,"Generando la Licencia...");
}

function internalAddLicencia()
{
	var newDate=new Date();
	MyROW=Ctrl("arrLicencias").AddRow();
	MyROW.SetAttr("id"            ,"#"+datetime2str(newDate));
	MyROW.SetAttr("oi_licencia"   ,"");
	MyROW.SetAttr("f_inicio"      ,"");
	MyROW.SetAttr("f_fin"         ,"");
	MyROW.SetAttr("e_cant_dias"   ,"");
	MyROW.SetAttr("e_anio_corresp","");
	MyROW.SetAttr("f_interrupcion","");
	MyROW.SetAttr("o_licencia_per","");
	MyROW.SetAttr("oi_familiar_per","");

	Ctrl("oi_licencia"   ).SetXValue(MyROW.GetAttr("oi_licencia"   ));
	Ctrl("f_inicio"      ).SetXValue(MyROW.GetAttr("f_inicio"      ));
	Ctrl("f_fin"         ).SetXValue(MyROW.GetAttr("f_fin"         ));
	Ctrl("e_cant_dias"   ).SetXValue(MyROW.GetAttr("e_cant_dias"   ));
	Ctrl("e_anio_corresp").SetXValue(MyROW.GetAttr("e_anio_corresp"));
	Ctrl("f_interrupcion").SetXValue(MyROW.GetAttr("f_interrupcion"));
	Ctrl("o_licencia_per").SetXValue(MyROW.GetAttr("o_licencia_per"));
	Ctrl("oi_familiar_per").SetXValue(MyROW.GetAttr("oi_familiar_per"));

	MyLICSel=MyROW;
	StartEdit();
	New=true;
	ReDrawWait(MyOBJ,"LIC",true, true);	
} 


function StartEdit()
{            
	var now, cur;	
	//Si intento modificar una licencia seleccionada - debo revisar si es de tipo familiar enfermo
	if(Ctrl("oi_licencia").GetXValue() != '')
	{
		//Recupero el codigo de la licencia - asociada al tipo de hora seleccionada en el control de oi_licencia
		var np = new NomadProxy("", ut);
		var nSQL = np.SQLService();       
		var param = nSQL.GetOBJ(Ctrl("main").getResource("qry_CodLic"), "<PARAM oi_licencia=\""+Ctrl('oi_licencia').GetXValue()+"\" />");	    	    

		var c_lic = param.c_licencia; 			    		    						  		
        var codLicFliar = Ctrl('codLicFliar').GetXValue().toString(); 	                 

		if(codLicFliar.toString() == c_lic.toString())
		{	
			Ctrl('oi_familiar_per').SetEnabled(true);
		}         	
		else
		{
			Ctrl('oi_familiar_per').SetEnabled(false);
		}	
	}	 

	//Verifico si el rango de dias esta bloqueado
	if (MyLICSel.GetAttr("f_inicio")!="")
	{   

		var dias;
		if(Ctrl('CantidadDiasModificar') != undefined)
			dias = Ctrl('CantidadDiasModificar').GetXValue();
		else
			dias = 180;

		now=NowDate();
		if ((NowDate()-str2date(MyLICSel.GetAttr("f_inicio")))/86400000>dias)
		{
			alert("No se puede modificar.\r\nLa fecha inicial es anterior a "+dias+" dias.");
			return false;
		}

		for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
		{                                
			if (MyLICSel.GetAttr("f_inicio")>cur.GetAttr("f_fin")) continue;
			if (MyLICSel.GetAttr("f_fin"   )<cur.GetAttr("f_ini")) continue;

			alert("No se puede modificar.\r\nExisten procesamientos cerrados en el rango de fechas.");
			return false;
		}
	}  

	Edit=true;

	MyOBJ.EditStart();           
	MyOBJ.SelectStyle("00AA00","BAR");

    RefreshControls();
}          





function EditCancel()
{        
	if (New)
	{
		Ctrl("arrLicencias").DelRowByAttr("id", MyLICSel.GetAttr("id"));
		MyLICSel=null;
	} else
	{
		Ctrl("oi_licencia"   ).SetXValue(MyLICSel.GetAttr("oi_licencia"   ));
		Ctrl("f_inicio"      ).SetXValue(MyLICSel.GetAttr("f_inicio"      ));
		Ctrl("f_fin"         ).SetXValue(MyLICSel.GetAttr("f_fin"         ));
		Ctrl("e_cant_dias"   ).SetXValue(MyLICSel.GetAttr("e_cant_dias"   ));
		Ctrl("e_anio_corresp").SetXValue(MyLICSel.GetAttr("e_anio_corresp"));
		Ctrl("f_interrupcion").SetXValue(MyLICSel.GetAttr("f_interrupcion"));
		Ctrl("o_licencia_per").SetXValue(MyLICSel.GetAttr("o_licencia_per"));
		Ctrl("oi_familiar_per").SetXValue(MyLICSel.GetAttr("oi_familiar_per"));		
	}
	Edit=false;
	New=false;

	MyOBJ.EditEnd();          
	ReDrawWait(MyOBJ,"LIC",true, true);
}       

function ChangeTime(obj, myserie, timestart, timeend)
{                               
	if (myserie!="LIC") return;

	aux=str2date("20000102"); aux.setDate(aux.getDate()+timestart); Ctrl("f_inicio").SetXValue(date2str(aux));
	aux=str2date("20000102"); aux.setDate(aux.getDate()+timeend-1); Ctrl("f_fin"   ).SetXValue(date2str(aux));

	if (Ctrl("e_anio_corresp").GetXValue()=="") 
		Ctrl("e_anio_corresp").SetTypedValue(Ctrl("f_inicio").TypedValue().getFullYear());
	Ctrl("e_cant_dias").SetTypedValue((Ctrl("f_fin").TypedValue()-Ctrl("f_inicio").TypedValue())/86400000+1);

	ReDrawWait(MyOBJ,"LIC",true, true);
}

function EditAccept()
{    
	var t, cur; 

  //valido licencia actual
  if(!validarDiasPedidos())
  	return false;


	var dias;
	if(Ctrl('CantidadDiasModificar') != undefined)
		dias = Ctrl('CantidadDiasModificar').GetXValue();
	else
		dias = 180;

	if ((NowDate()-str2date(Ctrl("f_inicio").GetXValue()))/86400000>dias)
	{
		alert("No se puede modificar.\r\nEl inicio del rango es anterior a "+dias+" dias.");       
		return false;
	}

	for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
	{                                
		if (Ctrl("f_inicio").GetXValue()>cur.GetAttr("f_fin")) continue;
		if (Ctrl("f_fin").GetXValue()<cur.GetAttr("f_ini")) continue;

		alert("No se puede modificar.\r\nExisten procesamientos cerrados en el rango de fechas.");
		return false;
	}

	for (t=0; t<Ctrl("arrLicencias").CountRow(); t++)
	{
		MyROW=Ctrl("arrLicencias").GetRow(t);
		if (MyROW.GetAttr("id")==MyLICSel.GetAttr("id")) continue;

		if (Ctrl("f_inicio").GetXValue()>MyROW.GetAttr("f_fin")   ) continue;
		if (Ctrl("f_fin"   ).GetXValue()<MyROW.GetAttr("f_inicio")) continue;

		//falta verificacion de rango 
		alert("La Licencia modificada se superpone con otra Licencia.");
		return false;
	}

	NomadTimeout("internalEditAccept()",100,"Actualizando la Vista...");
}

function internalEditAccept()
{
	MyLICSel.SetAttr("oi_licencia"   ,Ctrl("oi_licencia"   ).GetXValue());
	MyLICSel.SetAttr("f_inicio"      ,Ctrl("f_inicio"      ).GetXValue());
	MyLICSel.SetAttr("f_fin"         ,Ctrl("f_fin"         ).GetXValue());
	MyLICSel.SetAttr("e_cant_dias"   ,Ctrl("e_cant_dias"   ).GetXValue());
	MyLICSel.SetAttr("e_anio_corresp",Ctrl("e_anio_corresp").GetXValue());
	MyLICSel.SetAttr("f_interrupcion",Ctrl("f_interrupcion").GetXValue());
	MyLICSel.SetAttr("o_licencia_per",Ctrl("o_licencia_per").GetXValue());
	MyLICSel.SetAttr("oi_familiar_per",Ctrl("oi_familiar_per").GetXValue());

	Edit=false;
	New=false;

	GetLicSel(MyDAT, Ctrl("oi_licencia").GetXValue());

	MyOBJ.EditEnd();  
	OnChangePeriodo();
	RefreshControls();     
}


function ChangeFInicio()
{ 
	if (Ctrl("f_inicio").GetXValue()=="") 
		return true;

	//Calculo el año a partir de la fecha de inicio		
	if (Ctrl("e_anio_corresp").GetXValue()=="") 
	{
		Ctrl("e_anio_corresp").SetTypedValue(Ctrl("f_inicio").TypedValue().getFullYear());
		calcularSaldo(0);
	}

	if (Ctrl("f_fin").GetXValue()!="")
		Ctrl("e_cant_dias").SetTypedValue((Ctrl("f_fin").TypedValue()-Ctrl("f_inicio").TypedValue())/86400000+1);

	ReDrawWait(MyOBJ,"LIC",true, false);
}

function ChangeFFin()
{
	if (Ctrl("f_fin").GetXValue()=="") 
		return true;

	if (Ctrl("f_inicio").GetXValue()!="")
		Ctrl("e_cant_dias").SetTypedValue((Ctrl("f_fin").TypedValue()-Ctrl("f_inicio").TypedValue())/86400000+1);

	ReDrawWait(MyOBJ,"LIC",true, false);
}

function ChangeDias()
{
	if (Ctrl("e_cant_dias").GetXValue()=="") 
		return true;

	if (Ctrl("f_inicio").GetXValue()!="")       
	{
		aux=Ctrl("f_inicio").TypedValue();
		aux.setDate(aux.getDate()+Ctrl("e_cant_dias").TypedValue()-1);
		Ctrl("f_fin").SetTypedValue(aux);
	}      	

	ReDrawWait(MyOBJ,"LIC",true, false);
}

function validar_f_fin(myThis)
{	                            
	if (myThis.GetXValue() < Ctrl('f_inicio').GetXValue())
	{
		myThis.SetError("La fecha de Fin debe ser posterior o igual a la fecha de Inicio");
		return false;
	}
	else 
		return true;
}

function DelLicencia()
{  
	var now, maxfecha;

	var dias;
	if(Ctrl('CantidadDiasModificar') != undefined)
		dias = Ctrl('CantidadDiasModificar').GetXValue();
	else
		dias = 180;

	//Verifico si el dia esta bloqueado
	if ((NowDate()-str2date(MyLICSel.GetAttr("f_fin")))/86400000>dias)
	{       
		alert("No se puede Eliminar.\r\nLa fecha final es anterior a "+dias+" dias.");
		return false;
	}

	if ((NowDate()-str2date(MyLICSel.GetAttr("f_inicio")))/86400000>dias)
	{
		alert("No se puede Eliminar.\r\nExisten procesamientos cerrados en el rango de fechas.");       
		return false;
	}

	for (cur=LiqCloses.FirstChild(); cur!=null; cur=cur.Next())
	{                                
		if (MyLICSel.GetAttr("f_inicio")>cur.GetAttr("f_fin")) continue;
		if (MyLICSel.GetAttr("f_fin")<cur.GetAttr("f_ini")) continue;

		alert("No se puede Eliminar.\r\nExisten procesamientos cerrados en el rango de fechas.");       
		return false;
	}

	Ctrl("arrLicencias").DelRowByAttr("id", MyLICSel.GetAttr("id"));
	MyLICSel=null;
	ReDrawWait(MyOBJ,"LIC", true, true);
}

function SetData(NAME, KEY)
{
	if (Ctrl("main").GetMode()!="EDIT") return;

	MyDAT[NAME].sel=KEY;     
	if (MyDAT[NAME].cont!="") DrawReference(MyDAT[NAME], MyDAT[NAME].cont);

	if ((NAME=="LIC") && (Edit))
		Ctrl("oi_licencia").SetXValue(MyDAT[NAME].arr[KEY].lic);
}
//********************************************************************************************

function calcularSaldoTotal(oi_licencia, e_anio_corresp)
{
	var saldoTotal=0;
	for (t=0; t<Ctrl("arrLicencias").CountRow(); t++)
	{
		MyROW=Ctrl("arrLicencias").GetRow(t);

		if (MyROW.GetAttr("oi_licencia")==oi_licencia && MyROW.GetAttr("e_anio_corresp")==e_anio_corresp)
		{
			saldoTotal=saldoTotal+parseInt(MyROW.GetAttr("e_cant_dias"));	
		}	
	}

	return saldoTotal;
}

function calcularSaldo(cant_licencia)
{       
	if ((Ctrl('e_anio_corresp').GetCValue() != "") || (Ctrl('oi_licencia').GetXValue() != ""))
	{   
	  var licRes;
	  var nSQL = GetProxy().SQLService(); 	  
	  licRes = nSQL.GetOBJ(Ctrl("main").getResource("qry_datosLic"), "<PARAM oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" oi_licencia=\""+Ctrl('oi_licencia').GetXValue()+"\" oi_tipo_familiar=\""+Ctrl('oi_tipo_familiar').GetXValue()+"\" />");

		licRes = nSQL.GetOBJ(Ctrl("main").getResource("qry_datosLic"), "<PARAM oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" oi_licencia=\""+Ctrl('oi_licencia').GetXValue()+"\" oi_tipo_familiar=\""+Ctrl('oi_tipo_familiar').GetXValue()+"\" />");

	  if(licRes.e_max_dias_anio!='null')	  	  
	  	Ctrl('e_max_dias_anio').SetXValue(licRes.e_max_dias_anio);
	  else
	  	Ctrl('e_max_dias_anio').SetXValue('');

	  if(licRes.e_max_dias_lic!='null')	  	  
	  	Ctrl('e_max_dias_lic').SetXValue(licRes.e_max_dias_lic);
	  else
	  	Ctrl('e_max_dias_lic').SetXValue('');	

	  if(licRes.e_min_meses_antig!='null')	  	  
	  	Ctrl('e_min_meses_antig').SetXValue(licRes.e_min_meses_antig);
	  else
	  	Ctrl('e_min_meses_antig').SetXValue('');	

	  if(licRes.l_max_dias_anio!='null')	  	  
	  	Ctrl('l_max_dias_anio').SetXValue(licRes.l_max_dias_anio);
	  else
	  	Ctrl('l_max_dias_anio').SetXValue('');	

