	Ctrl('e_anio_corresp').SetTypedValue(fecha);
	Ctrl('e_cant_dias').SetXValue("");
	Ctrl('f_fin').SetXValue("");

}

//Calcula la antiguedad del legajo en meses
function calcularAntiguedad()
{
	var antiguedad;  
	var nSQL = GetProxy().SQLService();
	antiguedad = nSQL.GetOBJ(Ctrl("main").getResource("qry_Antiguedad"), "<PARAM oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" />");    

	var d1 = new Date(antiguedad.f_ant_calculo.substr(0,4),parseInt(antiguedad.f_ant_calculo.substr(4,2))-1, antiguedad.f_ant_calculo.substr(6,2));
	var d2 = new Date();     

	return monthDiff(d1,d2);
} 

//Calcula Diferencia en Meses entre dos Fechas
function monthDiff(d1, d2) {
    var months;
    months = (d2.getFullYear() - d1.getFullYear()) * 12;
    var fechaActual= new Date();        
    //Si la fecha corresponde al corriente año
    if(fechaActual.getFullYear()==d1.getFullYear())
    	{
    	//Si d1 arranca en el primer día no descuenta el primer mes      
    	if(d1.getDay()==1)
    		months -= (d1.getMonth()-1);
    	else
    		months -= d1.getMonth();
    	}
    else
    	{
    	//Si d1 arranca en el primer día no descuenta el primer mes      
    	if(d1.getDay()==0)
    		months -= (d1.getMonth()-1);
    	else
    		months -= d1.getMonth();
    	}	                             

    //Obtiene el último día del mes  
   	var ultimoDia = new Date(2016,d2.getMonth()+1,0); 
   	//Si el último mes se trabajo completo, suma también el último mes 
   	if(d2.getDay()!=ultimoDia.getDay())
    	months += d2.getMonth();
    else
    	months += d2.getMonth()+1;

    return months <= 0 ? 0 : months;
}  	

