function GetLicSel(MyDAT, oi_licencia)
{	
	var PARAM = "<DATO oi_licencia=\""+oi_licencia+"\"/>";
	proxy=new NomadProxy();	
	var sellic=proxy.SQLService().GetOBJ(Ctrl("main").getResource("SELLIC"),PARAM);
	RESULT=sellic["TIPOS_DE_HORA"];	

	for (t=0; t<RESULT.Child.length; t++)
	{
		MyDAT["LIC"].arr[RESULT.Child[t].id.toString()]=RESULT.Child[t];
		if (MyDAT["LIC"].def==null) MyDAT["LIC"].def=RESULT.Child[t];
	}
	DrawReference(MyDAT["LIC"], MyDAT["LIC"].cont);
}

function calcular_dias(myThis)
{       
	//sugiero año corresp. si lo llamo desde f_inicio	
	if(((myThis.ID()=='f_inicio') || (myThis.ID()=='oi_personal_emp') || (myThis.ID()=='oi_licencia') || (myThis.ID()=='oi_familiar_per')) && (Ctrl('f_inicio').GetCValue()!=""))
	{		
		sugerirAnoCorresp();
		calcularSaldo();
	} 

	if (CtrlExists("l_bloqueada") && (Ctrl("l_bloqueada").GetXValue()=="1")) return true;

 	if (Ctrl('f_fin').GetXValue() != "" && Ctrl('f_inicio').GetXValue() != "")
 	{ 		
 		if (Ctrl('f_fin').GetXValue() >= Ctrl('f_inicio').GetXValue())
 		{
 			Ctrl('e_cant_dias').SetTypedValue(DiffDays(Ctrl('f_fin').TypedValue(), Ctrl('f_inicio').TypedValue()) + 1);
 		} 
 		else Ctrl('e_cant_dias').SetXValue("");
 	}
 	else Ctrl('e_cant_dias').SetXValue("");     	

	ReDrawWait(MyOBJ,"LIC",true, false);

 	return true;

}

